  "content": "#!/usr/bin/env python3\n\n\"\"\"\nDigital Clock - Multiple Time Zones\nDisplay current time in different time zones with real-time updates\n\"\"\"\n\nimport datetime\nimport pytz\nimport time\nimport os\nfrom datetime import datetime as dt\n\nclass DigitalClock:\n    def __init__(self):\n        self.timezones = {\n            'UTC': 'UTC',\n            'EST': 'America/New_York',\n            'CST': 'America/Chicago',\n            'MST': 'America/Denver',\n            'PST': 'America/Los_Angeles',\n            'GMT': 'Europe/London',\n            'CET': 'Europe/Paris',\n            'IST': 'Asia/Kolkata',\n            'JST': 'Asia/Tokyo',\n            'AEST': 'Australia/Sydney',\n            'NZST': 'Pacific/Auckland',\n            'SGT': 'Asia/Singapore'\n        }\n        \n        self.selected_zones = ['UTC', 'EST', 'PST', 'GMT', 'JST']\n    \n    def clear_screen(self):\n        \"\"\"Clear console screen\"\"\"\n        os.system('cls' if os.name == 'nt' else 'clear')\n    \n    def get_time_in_zone(self, timezone_code):\n        \"\"\"Get current time in specified timezone\"\"\"\n        tz = pytz.timezone(self.timezones[timezone_code])\n        return dt.now(tz)\n    \n    def format_digital_display(self, time_obj, timezone_code):\n        \"\"\"Format time as digital clock display\"\"\"\n        hour = time_obj.strftime('%H')\n        minute = time_obj.strftime('%M')\n        second = time_obj.strftime('%S')\n        \n        # Create 7-segment style display\n        display = f\"\"\"\n    ╔════════════════════════════════════╗\n    ║  {timezone_code:^32}  ║\n    ╠════════════════════════════════════╣\n    ║                                    ║\n    ║       ██████    ██████    ██████   ║\n    ║      ██    ██  ██    ██  ██    ██  ║\n    ║      ██ {hour[0]}  ██  ██ {minute[0]}  ██  ██ {second[0]}  ██  ║\n    ║      ██    ██  ██    ██  ██    ██  ║\n    ║       ██████    ██████    ██████   ║\n    ║           ██        ██        ██   ║\n    ║      ██ {hour[1]}  ██  ██ {minute[1]}  ██  ██ {second[1]}  ██  ║\n    ║      ██    ██  ██    ██  ██    ██  ║\n    ║       ██████    ██████    ██████   ║\n    ║                                    ║\n    ║         {hour}:{minute}:{second}                      ║\n    ║                                    ║\n    ║  {time_obj.strftime('%A, %B %d, %Y'):^32}  ║\n    ║                                    ║\n    ╚════════════════════════════════════╝\n        \"\"\"\n        return display\n    \n    def display_all_zones(self):\n        \"\"\"Display clock for all selected zones\"\"\"\n        self.clear_screen()\n        \n        print(\"\\n\" + \"=\"*80)\n        print(\"⏰ DIGITAL CLOCK - MULTIPLE TIME ZONES ⏰\".center(80))\n        print(\"=\"*80 + \"\\n\")\n        \n        for zone in self.selected_zones:\n            time_obj = self.get_time_in_zone(zone)\n            print(self.format_digital_display(time_obj, zone))\n            print()\n    \n    def display_simple_format(self):\n        \"\"\"Display in simple format\"\"\"\n        self.clear_screen()\n        \n        print(\"\\n\" + \"╔\" + \"═\"*78 + \"╗\")\n        print(\"║ \" + \"⏰ WORLD CLOCK - CURRENT TIME IN MULTIPLE TIME ZONES ⏰\".center(76) + \" ║\")\n        print(\"╚\" + \"═\"*78 + \"╝\\n\")\n        \n        for zone in self.selected_zones:\n            time_obj = self.get_time_in_zone(zone)\n            time_str = time_obj.strftime('%H:%M:%S')\n            date_str = time_obj.strftime('%A, %B %d, %Y')\n            utc_offset = time_obj.strftime('%z')\n            \n            print(f\"  {zone:6} │ {time_str} │ {date_str:30} │ UTC{utc_offset[:3]}:{utc_offset[3:]}\")\n        \n        print(\"\\n\" + \"─\"*80 + \"\\n\")\n    \n    def display_detailed_format(self):\n        \"\"\"Display detailed format with more information\"\"\"\n        self.clear_screen()\n        \n        print(\"\\n\" + \"╔\" + \"═\"*78 + \"╗\")\n        print(\"║ \" + \"⏰ DETAILED WORLD CLOCK ⏰\".center(76) + \" ║\")\n        print(\"╚\" + \"═\"*78 + \"╝\\n\")\n        \n        for zone in self.selected_zones:\n            time_obj = self.get_time_in_zone(zone)\n            \n            timezone_name = self.timezones[zone]\n            time_str = time_obj.strftime('%H:%M:%S')\n            date_str = time_obj.strftime('%A, %B %d, %Y')\n            utc_offset = time_obj.strftime('%z')\n            am_pm = time_obj.strftime('%p')\n            \n            print(f\"┌─ {zone} ({timezone_name}) \" + \"─\"*(78-len(zone)-len(timezone_name)-8))\n            print(f\"│ Time:        {time_str} {am_pm}\")\n            print(f\"│ Date:        {date_str}\")\n            print(f\"│ UTC Offset:  UTC{utc_offset[:3]}:{utc_offset[3:]}\")\n            print(f\"│ Timezone:    {timezone_name}\")\n            print(f\"└\" + \"─\"*78 + \"\\n\")\n    \n    def show_all_timezones(self):\n        \"\"\"Show all available timezones\"\"\"\n        print(\"\\n\" + \"=\"*80)\n        print(\"AVAILABLE TIME ZONES\".center(80))\n        print(\"=\"*80 + \"\\n\")\n        \n        for code, tz_name in sorted(self.timezones.items()):\n            time_obj = self.get_time_in_zone(code)\n            print(f\"  {code:6} - {tz_name:25} │ {time_obj.strftime('%H:%M:%S')}\")\n        \n        print(\"\\n\" + \"=\"*80 + \"\\n\")\n    \n    def select_timezones_menu(self):\n        \"\"\"Menu to select which timezones to display\"\"\"\n        while True:\n            self.clear_screen()\n            print(\"\\n\" + \"=\"*80)\n            print(\"SELECT TIME ZONES TO DISPLAY\".center(80))\n            print(\"=\"*80 + \"\\n\")\n            \n            print(\"Currently selected:\")\n            for i, zone in enumerate(self.selected_zones, 1):\n                print(f\"  {i}. {zone} - {self.timezones[zone]}\")\n            \n            print(\"\\n\" + \"─\"*80 + \"\\n\")\n            print(\"1. Add timezone\")\n            print(\"2. Remove timezone\")\n            print(\"3. Reset to default\")\n            print(\"4. Back to main menu\")\n            \n            choice = input(\"\\nSelect option (1-4): \").strip()\n            \n            if choice == '1':\n                self.add_timezone()\n            elif choice == '2':\n                self.remove_timezone()\n            elif choice == '3':\n                self.selected_zones = ['UTC', 'EST', 'PST', 'GMT', 'JST']\n                print(\"\\n✅ Reset to default time zones!\")\n                time.sleep(1)\n            elif choice == '4':\n                break\n            else:\n                print(\"\\n❌ Invalid option!\")\n                time.sleep(1)\n    \n    def add_timezone(self):\n        \"\"\"Add a timezone to display\"\"\"\n        self.clear_screen()\n        print(\"\\n\" + \"=\"*80)\n        print(\"ADD TIME ZONE\".center(80))\n        print(\"=\"*80 + \"\\n\")\n        \n        self.show_all_timezones()\n        \n        code = input(\"Enter timezone code (or press Enter to cancel): \").strip().upper()\n        \n        if code:\n            if code in self.timezones:\n                if code not in self.selected_zones:\n                    self.selected_zones.append(code)\n                    print(f\"\\n✅ Added {code}!\")\n                else:\n                    print(f\"\\n⚠️  {code} is already in the list!\")\n            else:\n                print(f\"\\n❌ Invalid timezone code!\")\n        \n        time.sleep(1)\n    \n    def remove_timezone(self):\n        \"\"\"Remove a timezone from display\"\"\"\n        self.clear_screen()\n        print(\"\\n\" + \"=\"*80)\n        print(\"REMOVE TIME ZONE\".center(80))\n        print(\"=\"*80 + \"\\n\")\n        \n        for i, zone in enumerate(self.selected_zones, 1):\n            print(f\"  {i}. {zone}\")\n        \n        try:\n            choice = int(input(\"\\nSelect timezone number to remove (or 0 to cancel): \"))\n            if 0 < choice <= len(self.selected_zones):\n                removed = self.selected_zones.pop(choice - 1)\n                print(f\"\\n✅ Removed {removed}!\")\n            elif choice != 0:\n                print(\"\\n❌ Invalid selection!\")\n        except ValueError:\n            print(\"\\n❌ Invalid input!\")\n        \n        time.sleep(1)\n    \n    def main_menu(self):\n        \"\"\"Main menu\"\"\"\n        while True:\n            self.clear_screen()\n            print(\"\\n\" + \"╔\" + \"═\"*78 + \"╗\")\n            print(\"║ \" + \"⏰ DIGITAL CLOCK - WORLD TIME ZONES ⏰\".center(76) + \" ║\")\n            print(\"╚\" + \"═\"*78 + \"╝\\n\")\n            \n            print(\"1. Display simple format (Real-time updates)\")\n            print(\"2. Display detailed format (Real-time updates)\")\n            print(\"3. Display 7-segment format (Real-time updates)\")\n            print(\"4. View all timezones\")\n            print(\"5. Select timezones\")\n            print(\"6. Exit\")\n            \n            choice = input(\"\\nSelect option (1-6): \").strip()\n            \n            if choice == '1':\n                self.run_simple_display()\n            elif choice == '2':\n                self.run_detailed_display()\n            elif choice == '3':\n                self.run_7segment_display()\n            elif choice == '4':\n                self.show_all_timezones()\n                input(\"Press Enter to continue...\")\n            elif choice == '5':\n                self.select_timezones_menu()\n            elif choice == '6':\n                print(\"\\n👋 Goodbye!\\n\")\n                break\n            else:\n                print(\"\\n❌ Invalid option!\")\n                time.sleep(1)\n    \n    def run_simple_display(self):\n        \"\"\"Run simple display with real-time updates\"\"\"\n        try:\n            while True:\n                self.display_simple_format()\n                print(\"Press Ctrl+C to return to menu\\n\")\n                print(\"Last updated: \" + dt.now().strftime('%H:%M:%S'))\n                time.sleep(1)\n        except KeyboardInterrupt:\n            pass\n    \n    def run_detailed_display(self):\n        \"\"\"Run detailed display with real-time updates\"\"\"\n        try:\n            while True:\n                self.display_detailed_format()\n                print(\"Press Ctrl+C to return to menu\\n\")\n                print(\"Last updated: \" + dt.now().strftime('%H:%M:%S'))\n                time.sleep(1)\n        except KeyboardInterrupt:\n            pass\n    \n    def run_7segment_display(self):\n        \"\"\"Run 7-segment display with real-time updates\"\"\"\n        try:\n            while True:\n                self.display_all_zones()\n                print(\"Press Ctrl+C to return to menu\\n\")\n                print(\"Last updated: \" + dt.now().strftime('%H:%M:%S'))\n                time.sleep(1)\n        except KeyboardInterrupt:\n            pass\n\ndef main():\n    \"\"\"Main entry point\"\"\"\n    clock = DigitalClock()\n    clock.main_menu()\n\nif __name__ == \"__main__\":\n    main()\n"
